/** @module sso-provider-create */

import { getComponentStyles } from '@auth0/universal-components-core';
import { useMemo } from 'react';

import ProviderConfigure from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-configure/provider-configure';
import { ProviderDetails } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-details';
import { ProviderSelect } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-select';
import { GateKeeper } from '@/components/auth0/shared/gate-keeper/gate-keeper';
import { Header } from '@/components/auth0/shared/header';
import { StyledScope } from '@/components/auth0/shared/styled-scope';
import { Wizard } from '@/components/auth0/shared/wizard';
import type { StepProps } from '@/components/auth0/shared/wizard';
import { useSsoProviderCreate } from '@/hooks/my-organization/use-sso-provider-create';
import { useSsoProviderCreateLogic } from '@/hooks/my-organization/use-sso-provider-create-logic';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import type {
  FormState,
  SsoProviderCreateHandlerProps,
  SsoProviderCreateLogicProps,
  SsoProviderCreateProps,
  SsoProviderCreateViewProps,
} from '@/types/my-organization/idp-management/sso-provider/sso-provider-create-types';

/**
 * SSO provider creation container component.
 * @param props - Component props
 * @param props.createAction - Configuration for the create action
 * @param props.backButton - Configuration for the back button
 * @param props.customMessages - Custom translation messages to override defaults
 * @param props.styling - Custom styling configuration with variables and classes
 * @param props.onNext - Callback for next action
 * @param props.onPrevious - Callback for previous action
 * @internal
 * @returns JSX element
 */
function SsoProviderCreate(props: SsoProviderCreateProps) {
  const {
    createAction,
    backButton,
    customMessages = {},
    styling = {
      variables: { common: {}, light: {}, dark: {} },
      classes: {},
    },
    onNext,
    onPrevious,
  } = props;

  const { createProvider, isCreating } = useSsoProviderCreate({
    createAction,
    customMessages,
  });
  const {
    formData,
    detailsRef,
    configureRef,
    setFormData,
    handleCreate,
    createStepActions,
    isLoadingConfig,
    filteredStrategies,
    isLoadingIdpConfig,
    idpConfig,
  } = useSsoProviderCreateLogic({
    onNext,
    onPrevious,
    createProvider,
  });

  const { strategy, details, configure } = formData;

  const ssoProviderCreateLogicProps: SsoProviderCreateLogicProps = {
    formData,
    strategy,
    details,
    configure,
    isCreating,
    isLoadingConfig,
    filteredStrategies,
    isLoadingIdpConfig,
    idpConfig,
    styling,
    customMessages,
    backButton,
  };

  const ssoProviderCreateHandlerProps: SsoProviderCreateHandlerProps = {
    onNext,
    onPrevious,
    setFormData,
    detailsRef,
    configureRef,
    handleCreate,
    createStepActions,
  };

  return (
    <GateKeeper styling={styling}>
      <SsoProviderCreateView
        logic={ssoProviderCreateLogicProps}
        handlers={ssoProviderCreateHandlerProps}
      />
    </GateKeeper>
  );
}

/**
 * Internal SSO provider creation view component
 * @param props - Component props
 * @param props.logic - Component logic props
 * @param props.handlers - Component handler props
 * @internal
 * @returns JSX element
 */
function SsoProviderCreateView({ logic, handlers }: SsoProviderCreateViewProps) {
  const {
    styling,
    customMessages,
    backButton,
    isCreating,
    strategy,
    details,
    configure,
    isLoadingConfig,
    filteredStrategies,
    isLoadingIdpConfig,
    idpConfig,
  }: SsoProviderCreateLogicProps = logic;

  const { isDarkMode } = useTheme();
  const { t } = useTranslator('idp_management.create_sso_provider', customMessages);
  const {
    detailsRef,
    configureRef,
    onNext,
    onPrevious,
    setFormData,
    handleCreate,
    createStepActions,
  }: SsoProviderCreateHandlerProps = handlers;

  const currentStyles = useMemo(
    () => getComponentStyles(styling, isDarkMode),
    [styling, isDarkMode],
  );

  const wizardSteps = useMemo(
    () => [
      {
        id: 'provider_select',
        title: t('steps.one'),
        content: ({ onNext: navigate }: StepProps) => (
          <ProviderSelect
            isLoading={isLoadingConfig}
            strategyList={filteredStrategies}
            onClickStrategy={(selected) => {
              setFormData((prev: FormState) => ({
                strategy: selected,
                details: prev.strategy === selected ? prev.details : null,
                configure: prev.strategy === selected ? prev.configure : null,
              }));
              onNext?.('provider_select', { strategy: selected });
              navigate?.();
            }}
            selectedStrategy={strategy}
            customMessages={customMessages?.provider_select}
            className={currentStyles?.classes?.['ProviderSelect-root']}
          />
        ),
        actions: { showNext: false },
      },
      {
        id: 'provider_details',
        title: t('steps.two'),
        content: () => (
          <ProviderDetails
            mode="create"
            ref={detailsRef}
            initialData={details ?? undefined}
            customMessages={customMessages?.provider_details}
            styling={styling}
            className={currentStyles?.classes?.['ProviderDetails-root']}
          />
        ),
        actions: createStepActions('provider_details', detailsRef),
      },
      {
        id: 'provider_configure',
        title: t('steps.three'),
        content: () =>
          strategy ? (
            <ProviderConfigure
              ref={configureRef}
              strategy={strategy}
              isLoading={isLoadingIdpConfig}
              initialData={configure ?? undefined}
              customMessages={customMessages?.provider_configure}
              idpConfig={idpConfig ?? null}
              className={currentStyles?.classes?.['ProviderConfigure-root']}
            />
          ) : null,
        actions: createStepActions('provider_configure', configureRef),
      },
    ],
    [
      t,
      strategy,
      details,
      configure,
      onNext,
      onPrevious,
      customMessages,
      currentStyles,
      styling,
      createStepActions,
    ],
  );

  return (
    <StyledScope style={currentStyles.variables}>
      <div className="w-full">
        <Header
          title={t('header.title')}
          backButton={
            backButton && {
              ...backButton,
              text: t('header.back_button_text'),
            }
          }
          className={currentStyles?.classes?.['SsoProviderCreate-header']}
        />
        <div className="sso-provider-create__content" data-testid="sso-provider-create-content">
          <Wizard
            isLoading={isCreating}
            hideStepperNumbers
            steps={wizardSteps}
            onComplete={handleCreate}
            formActionLabels={{
              nextButtonLabel: t('nextButtonLabel'),
              previousButtonLabel: t('previousButtonLabel'),
              completeButtonLabel: t('completeButtonLabel'),
            }}
            className={currentStyles?.classes?.['SsoProviderCreate-wizard']}
          />
        </div>
      </div>
    </StyledScope>
  );
}

/**
 * SSO provider creation wizard.
 *
 * Multi-step wizard for creating new SSO identity providers. Guides users through
 * provider selection, configuration, and setup. Supports OIDC, SAML, Google Workspace,
 * Microsoft Entra ID, Okta, PingFederate, and ADFS strategies.
 *
 * @param props - {@link SsoProviderCreateProps}
 * @param props.createAction - Lifecycle hooks for provider creation
 * @param props.backButton - Back button configuration
 * @param props.onNext - Callback when moving to next step
 * @param props.onPrevious - Callback when moving to previous step
 * @param props.customMessages - Custom i18n message overrides
 * @param props.styling - CSS variables and class overrides
 * @returns SSO provider creation wizard component
 *
 * @see {@link SsoProviderCreateProps} for full props documentation
 *
 * @example
 * ```tsx
 * <SsoProviderCreate
 *   createAction={{
 *     onBefore: (data) => true,
 *     onAfter: (provider) => navigate(`/providers/${provider.id}`),
 *   }}
 *   backButton={{
 *     onClick: () => navigate('/providers'),
 *   }}
 * />
 * ```
 */
export { SsoProviderCreate, SsoProviderCreateView };

/**
 * ADFS SSO provider configuration form.
 * @module adfs-sso-configure-form
 * @internal
 */

import {
  createProviderConfigureSchema,
  type AdfsConfigureFormValues,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import * as React from 'react';
import { useState } from 'react';
import { useForm } from 'react-hook-form';

import { CommonConfigureFields } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-configure/common-configure-fields';
import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import { FileUpload } from '@/components/ui/file-upload';
import {
  Form,
  FormField,
  FormItem,
  FormLabel,
  FormControl,
  FormMessage,
  FormDescription,
} from '@/components/ui/form';
import { Label } from '@/components/ui/label';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { ProviderConfigureFieldsProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-create-types';

export interface AdfsConfigureFormHandle {
  validate: () => Promise<boolean>;
  getData: () => AdfsConfigureFormValues;
  isDirty: () => boolean;
  reset: (data?: AdfsConfigureFormValues) => void;
}

interface AdfsConfigureFormProps extends Omit<ProviderConfigureFieldsProps, 'strategy'> {}

export const AdfsProviderForm = React.forwardRef<AdfsConfigureFormHandle, AdfsConfigureFormProps>(
  function AdfsProviderForm(
    { initialData, readOnly = false, customMessages = {}, className, onFormDirty, idpConfig },
    ref,
  ) {
    const { t } = useTranslator(
      'idp_management.create_sso_provider.provider_configure',
      customMessages,
    );

    const [uploadedFiles, setUploadedFiles] = useState<File[]>([]);

    const adfsData = initialData as AdfsConfigureFormValues | undefined;

    const form = useForm<AdfsConfigureFormValues>({
      resolver: zodResolver(createProviderConfigureSchema('adfs')),
      mode: 'onSubmit',
      reValidateMode: 'onChange',
      defaultValues: {
        meta_data_source: adfsData?.meta_data_source || 'meta_data_url',
        meta_data_location_url: adfsData?.meta_data_location_url || '',
        adfs_server: adfsData?.adfs_server || '',
        fedMetadataXml: adfsData?.fedMetadataXml || '',
      },
    });

    const { isDirty } = form.formState;

    React.useEffect(() => {
      onFormDirty?.(isDirty);
    }, [isDirty, onFormDirty]);

    React.useImperativeHandle(ref, () => ({
      validate: async () => {
        return await form.trigger();
      },
      getData: () => form.getValues(),
      isDirty: () => form.formState.isDirty,
      reset: (data) => {
        if (data) {
          form.reset(data);
        } else {
          form.reset();
        }
      },
    }));

    const typeValue = form.watch('meta_data_source');
    const showFederationMetadataFile = typeValue === 'meta_data_file';

    const handleFileUpload = async (files: File[]) => {
      setUploadedFiles(files);

      const file = files[0];
      if (file) {
        try {
          const content = await file.text();
          form.setValue('fedMetadataXml', content);
        } catch (error) {
          console.error('Error reading file:', error);
        }
      }
    };

    return (
      <Form {...form}>
        <div className={cn('space-y-6', className)}>
          <FormField
            control={form.control}
            name="meta_data_source"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                  {t('fields.adfs.meta_data_source.label')}
                </FormLabel>
                <FormControl>
                  <RadioGroup
                    value={field.value}
                    onValueChange={field.onChange}
                    disabled={readOnly}
                    className="flex flex-col space-y-2"
                  >
                    <div className="flex items-center space-x-2">
                      <RadioGroupItem value="meta_data_url" id="meta_data_url" />
                      <Label htmlFor="meta_data_url" className="text-sm font-normal cursor-pointer">
                        {t('fields.adfs.meta_data_source.options.meta_data_url.label')}
                      </Label>
                    </div>
                    <div className="flex items-center space-x-2">
                      <RadioGroupItem value="meta_data_file" id="meta_data_file" />
                      <Label
                        htmlFor="meta_data_file"
                        className="text-sm font-normal cursor-pointer"
                      >
                        {t('fields.adfs.meta_data_source.options.meta_data_file.label')}
                      </Label>
                    </div>
                  </RadioGroup>
                </FormControl>
                <FormMessage
                  role="alert"
                  className="text-sm text-left text-(length:--font-size-paragraph)"
                />
              </FormItem>
            )}
          />

          {typeValue === 'meta_data_url' && (
            <>
              <FormField
                control={form.control}
                name="adfs_server"
                render={({ field, fieldState }) => (
                  <FormItem>
                    <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                      {t('fields.adfs.meta_data_url.label')}
                    </FormLabel>
                    <FormControl>
                      <TextField
                        type="url"
                        placeholder={t('fields.adfs.meta_data_url.placeholder')}
                        error={Boolean(fieldState.error)}
                        readOnly={readOnly}
                        aria-required={true}
                        aria-invalid={Boolean(fieldState.error)}
                        {...field}
                      />
                    </FormControl>
                    <FormMessage
                      role="alert"
                      className="text-sm text-left text-(length:--font-size-paragraph)"
                    />
                    <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                      {t('fields.adfs.meta_data_url.helper_text')}
                    </FormDescription>
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="meta_data_location_url"
                render={({ field, fieldState }) => (
                  <FormItem>
                    <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                      {t('fields.adfs.meta_data_location_url.label')}
                    </FormLabel>
                    <FormControl>
                      <CopyableTextField
                        type="url"
                        placeholder={t('fields.adfs.meta_data_location_url.placeholder')}
                        error={Boolean(fieldState.error)}
                        readOnly={readOnly}
                        {...field}
                      />
                    </FormControl>
                    <FormMessage
                      role="alert"
                      className="text-sm text-left text-(length:--font-size-paragraph)"
                    />
                    <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                      {t('fields.adfs.meta_data_location_url.helper_text')}
                    </FormDescription>
                  </FormItem>
                )}
              />
            </>
          )}

          {showFederationMetadataFile && (
            <FormField
              control={form.control}
              name="fedMetadataXml"
              render={() => (
                <FormItem>
                  <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                    {t('fields.adfs.federation_metadata_file.label')}
                  </FormLabel>
                  <FormControl>
                    <div className="space-y-3">
                      <FileUpload
                        accept=".xml"
                        onChange={handleFileUpload}
                        value={uploadedFiles}
                        maxFiles={1}
                        disabled={readOnly}
                        className="w-full"
                        placeholder={t('fields.adfs.federation_metadata_file.placeholder')}
                      />
                    </div>
                  </FormControl>
                  <FormMessage
                    role="alert"
                    className="text-sm text-left text-(length:--font-size-paragraph)"
                  />
                  <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                    {t('fields.adfs.federation_metadata_file.helper_text')}
                  </FormDescription>
                </FormItem>
              )}
            />
          )}

          <CommonConfigureFields
            idpConfig={idpConfig}
            readOnly={readOnly}
            customMessages={customMessages}
          />
        </div>
      </Form>
    );
  },
);

/**
 * Common SSO provider configuration fields.
 * @module common-configure-fields
 * @internal
 */

import { useFormContext } from 'react-hook-form';

import { Checkbox } from '@/components/ui/checkbox';
import { FormField, FormItem, FormLabel, FormControl, FormDescription } from '@/components/ui/form';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { IdpConfig } from '@/types/my-organization/config/config-idp-types';

interface CommonConfigureFieldsProps {
  idpConfig: IdpConfig | null;
  readOnly?: boolean;
  customMessages?: Partial<Record<string, unknown>>;
}

/**
 * CommonConfigureFields Component
 * Renders common fields (show_as_button, assign_membership_on_login) that are shared across all SSO provider strategies
 * @param props - Component props.
 * @param props.idpConfig - Identity provider configuration
 * @param props.readOnly - Whether the component is in read-only mode
 * @param props.customMessages - Custom translation messages to override defaults
 * @returns JSX element
 */
export function CommonConfigureFields({
  idpConfig,
  readOnly = false,
  customMessages = {},
}: CommonConfigureFieldsProps) {
  const { t } = useTranslator(
    'idp_management.create_sso_provider.provider_configure',
    customMessages,
  );

  const form = useFormContext();

  // Only show these fields if the config allows them
  const showAsButtonEnabled = idpConfig?.organization?.can_set_show_as_button;
  const assignMembershipEnabled = idpConfig?.organization?.can_set_assign_membership_on_login;

  // If neither field is enabled, don't render anything
  if (!showAsButtonEnabled && !assignMembershipEnabled) {
    return null;
  }

  return (
    <div className="space-y-6 pt-4">
      {showAsButtonEnabled && (
        <FormField
          control={form.control}
          name="show_as_button"
          render={({ field }) => (
            <FormItem className="flex flex-row items-start space-x-3 space-y-0">
              <FormControl>
                <Checkbox
                  checked={field.value}
                  onCheckedChange={field.onChange}
                  disabled={readOnly}
                />
              </FormControl>
              <div className="space-y-1 leading-none">
                <FormLabel className="text-sm font-normal">
                  {t('fields.common.show_as_button.label')}
                </FormLabel>
                <FormDescription className="text-sm">
                  {t('fields.common.show_as_button.helper_text')}
                </FormDescription>
              </div>
            </FormItem>
          )}
        />
      )}

      {assignMembershipEnabled && (
        <FormField
          control={form.control}
          name="assign_membership_on_login"
          render={({ field }) => (
            <FormItem className="flex flex-row items-start space-x-3 space-y-0">
              <FormControl>
                <Checkbox
                  checked={field.value}
                  onCheckedChange={field.onChange}
                  disabled={readOnly}
                />
              </FormControl>
              <div className="space-y-1 leading-none">
                <FormLabel className="text-sm font-normal">
                  {t('fields.common.assign_membership_on_login.label')}
                </FormLabel>
                <FormDescription className="text-sm">
                  {t('fields.common.assign_membership_on_login.helper_text')}
                </FormDescription>
              </div>
            </FormItem>
          )}
        />
      )}
    </div>
  );
}

/**
 * Google Apps SSO provider configuration form.
 * @module google-apps-sso-configure-form
 * @internal
 */

import {
  createProviderConfigureSchema,
  type GoogleAppsConfigureFormValues,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import * as React from 'react';
import { useForm } from 'react-hook-form';

import { CommonConfigureFields } from '@/components/auth0/my-organization/shared/idp-management/sso-provider-create/provider-configure/common-configure-fields';
import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import {
  Form,
  FormField,
  FormItem,
  FormLabel,
  FormControl,
  FormMessage,
  FormDescription,
} from '@/components/ui/form';
import { TextField } from '@/components/ui/text-field';
import { useProviderFormMode } from '@/hooks/my-organization/use-provider-form-mode';
import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useTranslator } from '@/hooks/shared/use-translator';
import { cn } from '@/lib/utils';
import type { ProviderConfigureFieldsProps } from '@/types/my-organization/idp-management/sso-provider/sso-provider-create-types';

export interface GoogleAppsConfigureFormHandle {
  validate: () => Promise<boolean>;
  getData: () => GoogleAppsConfigureFormValues;
  isDirty: () => boolean;
  reset: (data?: GoogleAppsConfigureFormValues) => void;
}

interface GoogleAppsConfigureFormProps extends Omit<ProviderConfigureFieldsProps, 'strategy'> {}

export const GoogleAppsProviderForm = React.forwardRef<
  GoogleAppsConfigureFormHandle,
  GoogleAppsConfigureFormProps
>(function GoogleAppsProviderForm(
  {
    initialData,
    readOnly = false,
    customMessages = {},
    className,
    onFormDirty,
    idpConfig,
    mode = 'create',
  },
  ref,
) {
  const { t } = useTranslator(
    'idp_management.create_sso_provider.provider_configure',
    customMessages,
  );

  const { coreClient } = useCoreClient();
  const { showCopyButtons } = useProviderFormMode(mode);

  const callbackUrl = React.useMemo(() => {
    const domain = coreClient?.getDomain() || 'YOUR_DOMAIN';
    return `https://${domain}/login/callback`;
  }, [coreClient]);

  const googleAppsData = initialData as GoogleAppsConfigureFormValues | undefined;

  const form = useForm<GoogleAppsConfigureFormValues>({
    resolver: zodResolver(createProviderConfigureSchema('google-apps')),
    mode: 'onSubmit',
    reValidateMode: 'onChange',
    defaultValues: {
      domain: googleAppsData?.domain || '',
      client_id: googleAppsData?.client_id || '',
      client_secret: googleAppsData?.client_secret || '',
      callback_url: callbackUrl || '',
    },
  });

  const { isDirty } = form.formState;

  React.useEffect(() => {
    onFormDirty?.(isDirty);
  }, [isDirty, onFormDirty]);

  React.useImperativeHandle(ref, () => ({
    validate: async () => {
      return await form.trigger();
    },
    getData: () => form.getValues(),
    isDirty: () => form.formState.isDirty,
    reset: (data) => {
      if (data) {
        form.reset(data);
      } else {
        form.reset();
      }
    },
  }));

  return (
    <Form {...form}>
      <div className={cn('space-y-6', className)}>
        <FormField
          control={form.control}
          name="domain"
          render={({ field, fieldState }) => (
            <FormItem>
              <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                {t('fields.google-apps.domain.label')}
              </FormLabel>
              <FormControl>
                <TextField
                  type="text"
                  placeholder={t('fields.google-apps.domain.placeholder')}
                  error={Boolean(fieldState.error)}
                  readOnly={readOnly}
                  {...field}
                />
              </FormControl>
              <FormMessage
                role="alert"
                className="text-sm text-left text-(length:--font-size-paragraph)"
              />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="client_id"
          render={({ field, fieldState }) => (
            <FormItem>
              <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                {t('fields.google-apps.client_id.label')}
              </FormLabel>
              <FormControl>
                <CopyableTextField
                  type="text"
                  placeholder={t('fields.google-apps.client_id.placeholder')}
                  error={Boolean(fieldState.error)}
                  readOnly={readOnly}
                  showCopyButton={showCopyButtons}
                  {...field}
                />
              </FormControl>
              <FormMessage
                role="alert"
                className="text-sm text-left text-(length:--font-size-paragraph)"
              />
              <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                {t('fields.google-apps.client_id.helper_text')}
              </FormDescription>
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="client_secret"
          render={({ field, fieldState }) => (
            <FormItem>
              <FormLabel className="text-sm font-medium text-(length:--font-size-label)">
                {t('fields.google-apps.client_secret.label')}
              </FormLabel>
              <FormControl>
                <CopyableTextField
                  type="password"
                  placeholder={t('fields.google-apps.client_secret.placeholder')}
                  error={Boolean(fieldState.error)}
                  readOnly={readOnly}
                  showCopyButton={showCopyButtons}
                  {...field}
                />
              </FormControl>
              <FormMessage
                role="alert"
                className="text-sm text-left text-(length:--font-size-paragraph)"
