/**
 * Error handling hook with toast error.
 * @module use-error-handler
 */

import {
  isNotifiableError,
  resolveErrorMessage,
  getStatusCode,
  hasApiErrorBody,
  ERROR_CODES,
} from '@auth0/universal-components-core';
import { useCallback } from 'react';

import { showToast } from '@/components/auth0/shared/toast';
import { useTranslator } from '@/hooks/shared/use-translator';

interface ErrorHandlerCallOptions {
  fallbackMessage?: string;
}

/**
 * Hook for consistent error handling across the app.
 *
 * @returns Error handler function.
 *
 * @example
 * const handleError = useErrorHandler();
 *
 * // With custom message
 * onError: (error) => handleError(error, {
 *   fallbackMessage: t('my_error')
 * });
 *
 * // With defaults
 * onError: handleError;
 */
export function useErrorHandler() {
  const { t } = useTranslator('common');

  return useCallback(
    (error: unknown, options: ErrorHandlerCallOptions = {}): void => {
      if (!isNotifiableError(error)) return;

      const getCustomErrorMessage = (err: unknown): string | undefined => {
        const status = getStatusCode(err);
        switch (status) {
          case 400:
            return t('error.bad_request');
          case 401:
            return t('error.missing_token');
          case 403:
            return hasApiErrorBody(err) && err.body?.type?.includes(ERROR_CODES.INSUFFICIENT_SCOPE)
              ? t('error.insufficient_scope')
              : t('error.forbidden');
          case 404:
            return t('error.not_found');
          case 429:
            return t('error.rate_limit');
          default:
            return undefined;
        }
      };

      showToast({
        type: 'error',
        message:
          getCustomErrorMessage(error) ??
          resolveErrorMessage(error, options.fallbackMessage ?? t('error.generic')),
      });
    },
    [t],
  );
}

import { FACTOR_TYPE_RECOVERY_CODE, type MfaRequiredError } from '@auth0/universal-components-core';
import { useQuery } from '@tanstack/react-query';
import { useEffect, useMemo } from 'react';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';

/**
 * Resolves MFA enrollment factors and active authenticators for a step-up flow.
 *
 * Fetches enrollment factors (normal mode) or authenticators (proxy mode), falling back to
 * `error.mfa_requirements.enroll` when in proxy mode with no active authenticators.
 *
 * @param error - The MFA required error containing the `mfa_token` and optional requirements.
 * @returns Resolved `factors`, `authenticators`, `isEnrollMode`, and `isLoading`.
 * @internal
 */
export function useMfaRequirements(error: MfaRequiredError) {
  const { coreClient } = useCoreClient();
  const handleError = useErrorHandler();
  const mfaToken = error.mfa_token;

  const stepUpClient = coreClient?.getMFAStepUpApiClient();
  const isProxyMode = !!coreClient?.isProxyMode();

  const enrollment = useQuery({
    queryKey: ['mfa-enrollment-factors', mfaToken],
    queryFn: () => stepUpClient!.getEnrollmentFactors!(mfaToken),
    enabled: !!stepUpClient && !!stepUpClient.getEnrollmentFactors && !isProxyMode,
    select: (factors) => factors.filter((f) => f.type !== FACTOR_TYPE_RECOVERY_CODE),
    retry: false,
  });

  const authenticators = useQuery({
    queryKey: ['mfa-authenticators', mfaToken],
    queryFn: () => stepUpClient!.getAuthenticators(mfaToken),
    enabled: !!stepUpClient && (isProxyMode || (enrollment.isSuccess && !enrollment.data.length)),
    select: (items) => items.filter((a) => a.active),
    retry: false,
  });

  useEffect(() => {
    if (enrollment.isError) handleError(enrollment.error);
  }, [enrollment.isError, enrollment.error, handleError]);

  useEffect(() => {
    if (authenticators.isError) handleError(authenticators.error);
  }, [authenticators.isError, authenticators.error, handleError]);

  const factors = useMemo(() => {
    if (isProxyMode) {
      if (authenticators.isSuccess && authenticators.data.length === 0) {
        return (error.mfa_requirements?.enroll ?? []).filter(
          (f) => f.type !== FACTOR_TYPE_RECOVERY_CODE,
        );
      }
      return [];
    }
    return enrollment.data ?? [];
  }, [enrollment.data, authenticators.isSuccess, authenticators.data, isProxyMode, error]);

  return {
    factors,
    authenticators: authenticators.data ?? [],
    isEnrollMode: factors.length > 0,
    isLoading: enrollment.isLoading || authenticators.isLoading,
  };
}

/**
 * MFA step-up operations hook.
 * @module use-mfa-step-up
 * @internal
 */

import {
  type EnrollParams,
  type MfaRequiredError,
  type VerifyParams,
} from '@auth0/universal-components-core';
import { useCallback, useState } from 'react';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';

interface UseMfaStepUpProps {
  error: MfaRequiredError;
  onComplete: () => void;
}

/**
 * Wraps MFA step-up API operations with error handling and shared loading state.
 *
 * @param props - Hook configuration.
 * @param props.error - The MFA required error containing the `mfa_token`.
 * @param props.onComplete - Called after a successful `verify`.
 * @returns `enroll`, `challenge`, `verify`, and `isLoading`.
 * @internal
 */
export function useMfaStepUp({ error, onComplete }: UseMfaStepUpProps) {
  const { coreClient } = useCoreClient();
  const handleError = useErrorHandler();
  const stepUpClient = coreClient!.getMFAStepUpApiClient();

  const mfaToken = error.mfa_token;
  const [isLoading, setIsLoading] = useState(false);

  const enroll = useCallback(
    async (params: EnrollParams) => {
      setIsLoading(true);
      try {
        return await stepUpClient.enroll(params);
      } catch (err) {
        handleError(err);
        return undefined;
      } finally {
        setIsLoading(false);
      }
    },
    [stepUpClient, handleError],
  );

  const challenge = useCallback(
    async (authenticator: { id?: string }) => {
      try {
        return await stepUpClient.challenge({
          mfaToken,
          challengeType: 'oob',
          authenticatorId: authenticator.id,
        });
      } catch (err) {
        handleError(err);
        return undefined;
      }
    },
    [mfaToken, stepUpClient, handleError],
  );

  const verify = useCallback(
    async (params: VerifyParams) => {
      setIsLoading(true);
      try {
        await stepUpClient.verify(params);
        onComplete();
      } catch (err) {
        handleError(err);
      } finally {
        setIsLoading(false);
      }
    },
    [stepUpClient, handleError, onComplete],
  );

  return { enroll, challenge, verify, isLoading };
}

